    records.value = res.data.records
  } catch (e) { console.error(e) }
}

const fetchMessages = async () => {
  try {
    const res = await http.get('/message')
    messages.value = res.data.records
  } catch (e) { console.error(e) }
}

const deleteRecord = async (id: number) => {
  if (!confirm('确定要撤销这条发布吗？')) return
  try {
    const url = recordType.value === 'lost' ? `/my/lost/${id}` : `/my/found/${id}`
    await http.delete(url)
    fetchRecords()
    alert('已撤销并删除相关图片')
  } catch (e) { alert('操作失败') }
}

const editRecord = (item: any) => {
  if (recordType.value === 'lost') {
    router.push({ path: `/publish/lost/${item.id}` })
  } else {
    router.push({ path: '/publish/found', query: { id: item.id } })
  }
}

const markClaimed = async (id: number) => {
  try {
    const url = recordType.value === 'lost' ? `/my/lost/${id}/status` : `/my/found/${id}/status`
    await http.put(url, { status: 'CLAIMED' })
    fetchRecords()
  } catch (e) { alert('操作失败') }
}

const markAllRead = async () => {
  try {
    await http.put('/message/read-all')
    fetchMessages()
  } catch (e) { alert('操作失败') }
}

const readMsg = async (id: number) => {
  try {
    await http.put(`/message/${id}/read`)
    fetchMessages()
  } catch (e) { console.error(e) }
}

const delMsg = async (id: number) => {
  if (!confirm('确定要删除这条消息吗？')) return
  try {
    await http.delete(`/message/${id}`)
    fetchMessages()
  } catch (e) { alert('操作失败') }
}

const changePassword = async () => {
  if (pwdForm.value.newPassword !== pwdForm.value.confirmPassword) return alert('两次密码不一致')
  try {
    await http.post('/profile/password', pwdForm.value)
    alert('密码修改成功，请重新登录')
    showPwdModal.value = false
