<template>
  <div class="profile-page container">
    <div class="sidebar">
      <div class="user-card">
        <div class="avatar-wrapper">
          <img :src="user.avatar ? 'http://localhost:8080'+user.avatar : '/default-avatar.png'" alt="Avatar" class="avatar"/>
          <div class="avatar-mask" @click="triggerUpload">更换头像</div>
          <input type="file" ref="fileInput" @change="handleUpload" accept="image/*" hidden />
        </div>
        <h3 class="username">{{ user.nickname || user.username }}</h3>
        <p class="role-badge">{{ roleText }}</p>
      </div>

      <div class="menu">
        <div class="menu-item" :class="{active: currentTab==='info'}" @click="currentTab='info'">个人信息</div>
        <div class="menu-item" :class="{active: currentTab==='records'}" @click="currentTab='records'">我的发布</div>
        <div class="menu-item" :class="{active: currentTab==='claims'}" @click="currentTab='claims'">我的认领</div>
        <div class="menu-item" :class="{active: currentTab==='messages'}" @click="currentTab='messages'">消息中心</div>
        <div class="menu-item" :class="{active: currentTab==='security'}" @click="currentTab='security'">账号安全</div>
      </div>
    </div>

    <div class="content-area">
      <!-- Info Tab -->
      <div v-if="currentTab==='info'" class="tab-pane">
        <h2>个人信息</h2>
        <form @submit.prevent="updateProfile" class="profile-form">
          <div class="form-group">
            <label>账号</label>
            <input :value="user.username" disabled class="disabled-input"/>
          </div>
          <div class="form-group">
            <label>角色</label>
            <input :value="roleText" disabled class="disabled-input"/>
          </div>
          <div class="form-group">
            <label>昵称</label>
            <input v-model="form.nickname" placeholder="设置昵称"/>
          </div>
          <div class="form-group">
            <label>院系/部门</label>
            <select v-model="form.department" class="form-control">
              <option value="" disabled>请选择院系</option>
              <option v-for="dept in departments" :key="dept" :value="dept">{{ dept }}</option>
            </select>
          </div>
          <div class="form-group">
            <label>手机号码</label>
            <input v-model="form.phone" placeholder="联系电话"/>
          </div>
          <div class="form-group">
            <label>电子邮箱</label>
            <input v-model="form.email" type="email" placeholder="Email"/>
          </div>
          <div class="form-group">
            <label>个人简介</label>
            <textarea v-model="form.bio" rows="3"></textarea>
          </div>
          <button type="submit" class="save-btn">保存修改</button>
        </form>
      </div>

      <!-- Records Tab -->
      <div v-if="currentTab==='records'" class="tab-pane">
        <div class="sub-tabs">
          <span :class="{active: recordType==='lost'}" @click="recordType='lost'">我的失物</span>
          <span :class="{active: recordType==='found'}" @click="recordType='found'">我的拾物</span>
        </div>
        
        <div style="margin-bottom: 16px; display: flex; justify-content: flex-end;">
             <button class="primary-btn" @click="$router.push('/publish/lost')" v-if="recordType==='lost'">+ 发布失物</button>
             <button class="primary-btn" @click="$router.push('/publish/found')" v-if="recordType==='found'">+ 发布拾物</button>
        </div>

        <div class="records-list">
          <div v-for="item in records" :key="item.id" class="record-item">
            <div class="record-thumb">
              <img :src="item.thumbnailUrl ? 'http://localhost:8080'+item.thumbnailUrl : '/placeholder.png'"/>
            </div>
            <div class="record-info">
              <h4>{{ item.title }} <span class="status-tag" :class="item.status">{{ statusText(item.status) }}</span></h4>
              <p>发布时间：{{ formatDate(item.createdAt) }}</p>
              <div class="actions">
                <button v-if="item.status==='PENDING'" @click="editRecord(item)">编辑</button>
                <button v-if="item.status==='PENDING'" @click="deleteRecord(item.id)">撤销发布</button>
                <button v-if="item.status==='APPROVED'" @click="markClaimed(item.id)">标记已认领</button>
                <button @click="$router.push(`/detail/${recordType}/${item.id}`)">查看详情</button>
              </div>
            </div>
          </div>
          <div v-if="records.length===0" class="empty">暂无记录</div>
        </div>
      </div>

      <!-- Messages Tab -->
      <div v-if="currentTab==='messages'" class="tab-pane">
        <div class="msg-header">
          <h2>消息中心</h2>
          <button @click="markAllRead" class="text-btn">全部已读</button>
        </div>
        <div class="msg-list">
          <div v-for="msg in messages" :key="msg.id" class="msg-item" :class="{unread: !msg.isRead}">
            <div class="msg-content">
              <span class="type-tag">{{ typeText(msg.type) }}</span>
              <h4>{{ msg.title }}</h4>
              <p>{{ msg.content }}</p>
              <span class="time">{{ formatDate(msg.createdAt) }}</span>
            </div>
            <div class="msg-actions">
              <button v-if="!msg.isRead" @click="readMsg(msg.id)">标为已读</button>
              <button @click="delMsg(msg.id)" class="del-btn">删除</button>
            </div>
          </div>
        </div>
      </div>

      <!-- Claims Tab (Placeholder) -->
      <div v-if="currentTab==='claims'" class="tab-pane">
         <h2>我的认领</h2>
         <p>暂无认领记录</p>
      </div>

      <!-- Security Tab -->
      <div v-if="currentTab==='security'" class="tab-pane">
        <h2>账号安全</h2>
        <div class="security-item">
          <div class="sec-info">
            <h4>登录密码</h4>
            <p>建议定期更换密码以保障账号安全</p>
          </div>
          <button @click="showPwdModal=true">修改密码</button>
        </div>
      </div>
    </div>

    <!-- Password Modal -->
    <div v-if="showPwdModal" class="modal-mask">
      <div class="modal-box">
        <h3>修改密码</h3>
        <input type="password" v-model="pwdForm.oldPassword" placeholder="原密码"/>
        <input type="password" v-model="pwdForm.newPassword" placeholder="新密码 (8-20位)"/>
        <input type="password" v-model="pwdForm.confirmPassword" placeholder="确认新密码"/>
        <div class="modal-actions">
          <button @click="showPwdModal=false">取消</button>
          <button @click="changePassword" class="primary">确认修改</button>
        </div>
      </div>
    </div>

    <ImageCropper v-if="showCropper && tempFile" :file="tempFile" @confirm="uploadCropped" @cancel="cancelCrop" />
  </div>
</template>

<script setup lang="ts">
import { ref, onMounted, computed, watch } from 'vue'
import { useStore } from 'vuex'
import { useRoute, useRouter } from 'vue-router'
import http from '../api/http'
import ImageCropper from '../components/ImageCropper.vue'

const store = useStore()
const route = useRoute()
const router = useRouter()
const currentTab = ref('info')
const recordType = ref('lost')
const showPwdModal = ref(false)
const fileInput = ref<HTMLInputElement|null>(null)

const showCropper = ref(false)
const tempFile = ref<File|null>(null)

const user = computed(() => store.state.auth.user || {})
const roleText = computed(() => {
  const map: any = { 'ROLE_STUDENT': '学生', 'ROLE_ADMIN': '管理员', 'ROLE_MANAGER': '负责人' }
  if (user.value.roles && user.value.roles.length > 0) {
    return user.value.roles.map((r: any) => map[r.code] || r.code).join(', ')
  }
  return map[user.value.role] || user.value.role || '未知角色'
})

const form = ref({
  nickname: '',
  department: '',
  phone: '',
  email: '',
  bio: ''
})

const departments = [
  '计算机科学与技术学院',
  '人工智能学院',
  '电子信息工程学院',
  '自动化学院',
  '机械工程学院',
  '材料科学与工程学院',
  '化学化工学院',
  '外国语学院',
  '理学院',
  '经济管理学院',
  '艺术设计学院',
  '马克思主义学院',
  '体育学院',
  '继续教育学院'
]

const pwdForm = ref({ oldPassword: '', newPassword: '', confirmPassword: '' })
const records = ref<any[]>([])
const messages = ref<any[]>([])

// Methods
const fetchProfile = async () => {
  try {
    const res = await http.get('/profile')
    const data = res.data
    form.value = { ...data }
    store.commit('auth/setUser', data)
  } catch (e) { console.error(e) }
}

const updateProfile = async () => {
  try {
    // Validate phone
    if (!/^\d{11}$/.test(form.value.phone)) {
      alert('手机号码必须为11位数字')
      return
    }

    // Default bio
    const bioToSave = form.value.bio && form.value.bio.trim() !== '' ? form.value.bio : '无'

    const payload = {
      nickname: form.value.nickname,
      department: form.value.department,
      phone: form.value.phone,
      email: form.value.email,
      bio: bioToSave
    }
    await http.put('/profile', payload)
    alert('保存成功')
    fetchProfile()
  } catch (e: any) { 
    console.error(e)
    alert('保存失败: ' + (e.response?.data?.message || e.message))
  }
}

const triggerUpload = () => fileInput.value?.click()
const handleUpload = (e: Event) => {
  const file = (e.target as HTMLInputElement).files?.[0]
  if (!file) return
  tempFile.value = file
  showCropper.value = true
  // Reset input
  if (fileInput.value) fileInput.value.value = ''
}

const cancelCrop = () => {
  showCropper.value = false
  tempFile.value = null
}

const uploadCropped = async (blob: Blob) => {
  const fd = new FormData()
  fd.append('file', blob, 'avatar.jpg')
  try {
    await http.post('/profile/avatar', fd)
    fetchProfile()
    alert('头像上传成功')
    showCropper.value = false
    tempFile.value = null
  } catch (e: any) { 
    console.error(e)
    alert(e.response?.data?.message || '上传失败') 
  }
}

const fetchRecords = async () => {
  try {
    const url = recordType.value === 'lost' ? '/my/lost' : '/my/found'
    const res = await http.get(url)
    records.value = res.data.records
  } catch (e) { console.error(e) }
}

const fetchMessages = async () => {
  try {
    const res = await http.get('/message')
    messages.value = res.data.records
  } catch (e) { console.error(e) }
}

const deleteRecord = async (id: number) => {
  if (!confirm('确定要撤销这条发布吗？')) return
  try {
    const url = recordType.value === 'lost' ? `/my/lost/${id}` : `/my/found/${id}`
    await http.delete(url)
    fetchRecords()
    alert('已撤销并删除相关图片')
  } catch (e) { alert('操作失败') }
}

const editRecord = (item: any) => {
  if (recordType.value === 'lost') {
    router.push({ path: `/publish/lost/${item.id}` })
  } else {
    router.push({ path: '/publish/found', query: { id: item.id } })
  }
}

const markClaimed = async (id: number) => {
  try {
    const url = recordType.value === 'lost' ? `/my/lost/${id}/status` : `/my/found/${id}/status`
    await http.put(url, { status: 'CLAIMED' })
    fetchRecords()
  } catch (e) { alert('操作失败') }
}

const markAllRead = async () => {
  try {
    await http.put('/message/read-all')
    fetchMessages()
  } catch (e) { alert('操作失败') }
}

const readMsg = async (id: number) => {
  try {
    await http.put(`/message/${id}/read`)
    fetchMessages()
  } catch (e) { console.error(e) }
}

const delMsg = async (id: number) => {
  if (!confirm('确定要删除这条消息吗？')) return
  try {
    await http.delete(`/message/${id}`)
    fetchMessages()
  } catch (e) { alert('操作失败') }
}

const changePassword = async () => {
  if (pwdForm.value.newPassword !== pwdForm.value.confirmPassword) return alert('两次密码不一致')
  try {
    await http.post('/profile/password', pwdForm.value)
    alert('密码修改成功，请重新登录')
    showPwdModal.value = false
    // logout logic
  } catch (e: any) { alert(e.response?.data?.message || '修改失败') }
}

const statusText = (s: string) => ({'PENDING':'待审核','APPROVED':'待认领','CLAIMED':'已认领'}[s] || s)
const formatDate = (ts: string) => new Date(ts).toLocaleString()
const typeText = (t: string) => ({AUDIT:'系统', MATCH:'匹配', CLAIM:'认领', NOTICE:'公告'} as any)[t] || '其他'

// Watchers
watch(currentTab, (val) => {
  if (val === 'records') fetchRecords()
  if (val === 'messages') fetchMessages()
})
watch(recordType, () => fetchRecords())

watch(() => route.query.tab, (val) => {
  if (val && typeof val === 'string') {
    if (['info', 'records', 'claims', 'messages', 'security'].includes(val)) {
      currentTab.value = val
    }
    if (val === 'mypost') {
      currentTab.value = 'records'
      recordType.value = 'lost'
    }
  }
}, { immediate: true })

onMounted(() => {
  fetchProfile()
})
</script>

